import sys
from collections import deque

def parse_input():
    input = sys.stdin.read
    data = input().split()

    c, r, e = int(data[0]), int(data[1]), int(data[2])
    robot1_c, robot1_r, robot1_d = int(data[3]) - 1, int(data[4]) - 1, data[5]
    robot2_c, robot2_r, robot2_d = int(data[6]) - 1, int(data[7]) - 1, data[8]

    horizontal_walls = []
    for i in range(9, len(data), 2):
        c1, r1 = int(data[i]) - 1, int(data[i + 1]) - 1
        horizontal_walls.append((c1, r1))

    vertical_walls = []
    for i in range(len(horizontal_walls) * 2 + 9, len(data), 2):
        c1, r1 = int(data[i]) - 1, int(data[i + 1]) - 1
        vertical_walls.append((c1, r1))

    return c, r, e, robot1_c, robot1_r, robot1_d, robot2_c, robot2_r, robot2_d, horizontal_walls, vertical_walls

def is_valid_move(c, r, walls):
    if (c, r) in walls:
        return False
    if (c + 1, r) in walls and c < c + 1:
        return False
    if (c, r + 1) in walls and r < r + 1:
        return False
    if (c + 1, r + 1) in walls and c < c + 1 and r < r + 1:
        return False
    return True

def get_next_positions(c, r, d):
    if d == 'N':
        return [(c, r - 1), (c, r)]
    elif d == 'E':
        return [(c + 1, r), (c, r)]
    elif d == 'S':
        return [(c, r), (c, r + 1)]
    elif d == 'W':
        return [(c, r), (c - 1, r)]

def bfs(c, r, e, robot1_c, robot1_r, robot1_d, robot2_c, robot2_r, robot2_d, horizontal_walls, vertical_walls):
    directions = ['N', 'E', 'S', 'W']
    visited = set()
    queue = deque([(robot1_c, robot1_r, robot1_d, robot2_c, robot2_r, robot2_d, 0, 0)])

    while queue:
        r1_c, r1_r, r1_d, r2_c, r2_r, r2_d, moves, bumps = queue.popleft()

        if (r1_c, r1_r, r1_d, r2_c, r2_r, r2_d) in visited:
            continue
        visited.add((r1_c, r1_r, r1_d, r2_c, r2_r, r2_d))

        if r1_r == 0 or r2_r == 0:
            return moves, bumps

        for d1 in directions:
            for d2 in directions:
                next_r1_positions = get_next_positions(r1_c, r1_r, d1)
                next_r2_positions = get_next_positions(r2_c, r2_r, d2)

                if len(next_r1_positions) == 0 or len(next_r2_positions) == 0:
                    continue

                new_r1_c, new_r1_r = next_r1_positions[0]
                new_r2_c, new_r2_r = next_r2_positions[0]

                if (new_r1_c, new_r1_r) in visited or (new_r2_c, new_r2_r) in visited:
                    continue

                if not is_valid_move(new_r1_c, new_r1_r, horizontal_walls + vertical_walls):
                    bumps += 1
                    continue

                if not is_valid_move(new_r2_c, new_r2_r, horizontal_walls + vertical_walls):
                    bumps += 1
                    continue

                if (new_r1_c, new_r1_r) == (new_r2_c, new_r2_r):
                    continue

                queue.append((new_r1_c, new_r1_r, d1, new_r2_c, new_r2_r, d2, moves + 1, bumps))

    return -1, -1

def main():
    c, r, e, robot1_c, robot1_r, robot1_d, robot2_c, robot2_r, robot2_d, horizontal_walls, vertical_walls = parse_input()
    result = bfs(c, r, e, robot1_c, robot1_r, robot1_d, robot2_c, robot2_r, robot2_d, horizontal_walls, vertical_walls)
    print(result[0], result[1])

if __name__ == "__main__":
    main()
